```csharp
public enum Color
{
    Red = 1,
    Green = 2,
    Blue = 3
}

public class ColorEnum
{
    public static ColorEnum Red { get; } = new ColorEnum(Color.Red, "Fire engine red");
    public static ColorEnum Green { get; } = new ColorEnum(Color.Green, "Bright green");
    public static ColorEnum Blue { get; } = new ColorEnum(Color.Blue, "Cerulean blue");

    public Color Value { get; }
    public string Description { get; }

    private ColorEnum(Color value, string description)
    {
        Value = value;
        Description = description;
    }

    public override string ToString()
    {
        return $"{Value} ({Description})";
    }
}

public class Program
{
    public static void Main(string[] args)
    {
        ColorEnum color = ColorEnum.Green;
        Console.WriteLine(color); // Output: Green (Bright green)
    }
}
```

